import openai, json
from typing import Dict

def extract_entities_relationships(text: str) -> Dict:
    prompt = f"""
Extract entities and relationships from this text.

Text: {text}

Return JSON:
{{
  "entities": [
    {{"name": "...", "type": "PERSON|ORG|CONCEPT|EVENT", "description": "..."}},
  ],
  "relationships": [
    {{"source": "...", "target": "...", "type": "...", "description": "..."}},
  ]
}}
"""
    response = openai.chat.completions.create(
        model="gpt-4o",
        messages=[{"role": "user", "content": prompt}],
        response_format={"type": "json_object"},
        temperature=0
    )
    return json.loads(response.choices[0].message.content)

graph_data = {"entities": [], "relationships": []}
for chunk in chunks:
    extracted = extract_entities_relationships(chunk["text"])
    graph_data["entities"].extend(extracted["entities"])
    graph_data["relationships"].extend(extracted["relationships"])

from neo4j import GraphDatabase
class Neo4jGraphBuilder: def __init__(self, uri: str, user: str, password: str): self.driver = GraphDatabase.driver(uri, auth=(user, password))
def add_entity(self, name: str, entity_type: str, description: str): with self.driver.session() as session: session.run( """ MERGE (e:Entity {name: $name}) SET e.type = $type, e.description = $description """, name=name, type=entity_type, description=description )
def add_relationship(self, source: str, target: str, rel_type: str, description: str): with self.driver.session() as session: session.run( """ MATCH (a:Entity {name: $source}) MATCH (b:Entity {name: $target}) MERGE (a)-[r:RELATES_TO {type: $rel_type}]->(b) SET r.description = $description """, source=source, target=target, rel_type=rel_type, description=description )

import networkx as nx
from networkx.algorithms import community
from typing import Dict, List
import openai

def detect_communities(G: nx.Graph) -> Dict[int, List[str]]:
    communities = community.louvain_communities(G)
    return {idx: list(comm) for idx, comm in enumerate(communities)}

def summarize_community(community_nodes: List[str], G: nx.Graph) -> str:
    subgraph = G.subgraph(community_nodes)
    nodes_desc = "\n".join([
        f"- {node}: {G.nodes[node].get('description', '')}"
        for node in community_nodes
    ])
    edges_desc = "\n".join([
        f"- {u} {data['type']} {v}"
        for u, v, data in subgraph.edges(data=True)
    ])
    prompt = f"""Summarize this community of related entities:

Entities:
{nodes_desc}

Relationships:
{edges_desc}

Provide a concise summary of what this community represents."""
    response = openai.chat.completions.create(
        model="gpt-4o",
        messages=[{"role": "user", "content": prompt}],
        temperature=0
    )
    return response.choices[0].message.content

def hierarchical_summarization(G: nx.Graph) -> Dict:
    summaries = {"global": None, "communities": {}, "entities": {}}
    for node in G.nodes():
        summaries["entities"][node] = G.nodes[node].get("description", "")
    communities = detect_communities(G)
    for comm_id, nodes in communities.items():
        if len(nodes) >= 5:  # skip trivial communities
            summaries["communities"][comm_id] = summarize_community(nodes, G)
    all_community_summaries = "\n\n".join(summaries["communities"].values())
    prompt = f"""Summarize the main themes across all communities:

{all_community_summaries}

Provide a high-level summary of the entire knowledge graph."""
    response = openai.chat.completions.create(
        model="gpt-4o",
        messages=[{"role": "user", "content": prompt}],
        temperature=0
    )
    summaries["global"] = response.choices[0].message.content
    return summaries
